                      <div><label className="text-sm font-semibold text-gray-400">Senha de Acesso</label><input type="password" required value={loginForm.senha} onChange={e => setLoginForm({...loginForm, senha: e.target.value})} className="w-full bg-gray-900 border border-gray-700 rounded-xl p-3 text-white focus:border-brandGreen outline-none mt-1" placeholder="••••••••"/></div>
