                                            <td className="px-6 py-4 font-bold text-white flex items-center gap-3"><div className="w-8 h-8 rounded-full flex items-center justify-center font-bold bg-brandGreen/20 text-brandGreen">{emp.nome.charAt(0).toUpperCase()}</div>{emp.nome}</td>
