                                                    {empLicenses.map(asg => (<span key={asg.assignment_id} className="bg-yellow-900/20 text-yellow-400 px-2 py-1 rounded text-[11px] border border-yellow-900/50 flex items-center gap-1 font-medium"><Database className="w-3 h-3"/> {asg.license.nome}</span>))}
